4	import { createClient } from '$lib/gql/client';
5	import { projectStore } from '$lib/stores/project.svelte';
6	
7	const PROJECTS_QUERY = gql`
8		query ProjectsForLayout {
9			projects {
10				edges {
11					node {
12						id
13						name
14						path
15					}
16				}
17			}
18		}
19	`;
20	
21	interface ProjectNode {
22		id: string;
23		name: string;
24		path: string;
25	}
26	
27	interface ProjectsResult {
28		projects: {
29			edges: Array<{ node: ProjectNode }>;
30		};
31	}
32	
33	// Hydrate projectStore from params.projectId on every navigation into this
34	// route subtree so deep-links and page reloads see a populated store. Without
35	// this, the sidebar at NavShell.svelte disables every link because
36	// projectStore.value is null — only ProjectPicker.onchange would set it.
37	export const load: LayoutLoad = async ({ params, fetch }) => {
38		const client = createClient(fetch as unknown as typeof globalThis.fetch);
39		const data = await client.request<ProjectsResult>(PROJECTS_QUERY);
40		const project = data.projects.edges
41			.map((e) => e.node)
42			.find((p) => p.id === params.projectId);
43		if (!project) {
44			throw error(404, `project ${params.projectId} not found`);
45		}
46		projectStore.set(project);
47		return { project };
48	};
