8	
9	// NodeStateSnapshot holds node identity data for resolver consumption.
10	type NodeStateSnapshot struct {
11		ID        string
12		Name      string
13		StartedAt time.Time
14		LastSeen  time.Time
15	}
16	
17	// BeadDependencySnapshot holds dependency data for resolver consumption.
18	type BeadDependencySnapshot struct {
19		IssueID     string
20		DependsOnID string
21		Type        string
22		CreatedAt   string
23		CreatedBy   string
24		Metadata    string
25	}
26	
27	// BeadSnapshot holds bead data for resolver consumption.
28	type BeadSnapshot struct {
29		ProjectID    string
30		ID           string
31		Title        string
32		Status       string
33		Priority     int
34		IssueType    string
35		Owner        string
36		CreatedAt    time.Time
37		CreatedBy    string
38		UpdatedAt    time.Time
39		Labels       []string
40		Parent       string
41		Description  string
42		Acceptance   string
43		Notes        string
44		Dependencies []BeadDependencySnapshot
45	}
46	
47	// StateProvider is the minimal interface the node/projects resolvers need.
48	type StateProvider interface {
49		GetNodeSnapshot() NodeStateSnapshot
50		GetProjectSnapshots(includeUnreachable bool) []*Project
51		GetProjectSnapshotByID(id string) (*Project, bool)
52		GetBeadSnapshots(status, label, projectID, search string) []BeadSnapshot
53		// GetBeadSnapshotsForProject returns snapshots for a single registered
54		// project without iterating any other projects' stores. Implementations
55		// MUST open only the named project's bead store. The resolver for
56		// Query.beadsByProject uses this path to avoid the N-project scan that
57		// backs the cross-project GetBeadSnapshots call (ddx-9ce6842a).
58		GetBeadSnapshotsForProject(projectID, status, label, search string) []BeadSnapshot
59		GetBeadSnapshot(id string) (*BeadSnapshot, bool)
60	
61		// Worker queries
62		GetWorkersGraphQL(projectID string) []*Worker
63		GetWorkerGraphQL(id string) (*Worker, bool)
64		GetWorkerLogGraphQL(id string) *WorkerLog
65		GetWorkerProgressGraphQL(id string) []*PhaseTransition
66		GetWorkerPromptGraphQL(id string) string
67	
68		// AgentSession queries
69		GetAgentSessionsGraphQL(startedAfter, startedBefore *time.Time) []*AgentSession
70		GetAgentSessionGraphQL(id string) (*AgentSession, bool)
71		GetSessionsCostSummaryGraphQL(projectID string, since, until *time.Time) *SessionsCostSummary
72	
73		// Exec queries
74		GetExecDefinitionsGraphQL(artifactID string) []*ExecutionDefinition
75		GetExecDefinitionGraphQL(id string) (*ExecutionDefinition, bool)
76		GetExecRunsGraphQL(artifactID, definitionID string) []*ExecutionRun
77		GetExecRunGraphQL(id string) (*ExecutionRun, bool)
78		GetExecRunLogGraphQL(runID string) *ExecutionRunLog
79	
80		// Coordinator queries
81		GetCoordinatorsGraphQL() []*CoordinatorMetricsEntry
82		GetCoordinatorMetricsByProjectGraphQL(projectRoot string) *CoordinatorMetrics
83	}
84	
85	// Node is the resolver for the node(id: ID!) field (Relay lookup by global ID).
86	func (r *queryResolver) Node(ctx context.Context, id string) (Node, error) {
87		if strings.HasPrefix(id, "node-") {
88			snap := r.State.GetNodeSnapshot()
89			if snap.ID != id {
90				return nil, nil
91			}
92			return nodeInfoFromSnapshot(snap), nil
93		}
94		if strings.HasPrefix(id, "proj-") {
95			proj, ok := r.State.GetProjectSnapshotByID(id)
96			if !ok {
97				return nil, nil
98			}
99			return proj, nil
100		}
101		return nil, nil
102	}
103	
104	// NodeInfo is the resolver for the nodeInfo field.
105	func (r *queryResolver) NodeInfo(ctx context.Context) (*NodeInfo, error) {
106		snap := r.State.GetNodeSnapshot()
107		return nodeInfoFromSnapshot(snap), nil
108	}
109	
110	// Projects is the resolver for the projects field.
111	func (r *queryResolver) Projects(ctx context.Context, first *int, after *string, last *int, before *string, includeUnreachable *bool) (*ProjectConnection, error) {
112		showAll := includeUnreachable != nil && *includeUnreachable
113		projects := r.State.GetProjectSnapshots(showAll)
114	
115		// Build full edge list with stable ID-based cursors.
116		all := make([]*ProjectEdge, len(projects))
117		for i, p := range projects {
118			all[i] = &ProjectEdge{
119				Node:   p,
120				Cursor: encodeStableCursor(p.ID),
121			}
122		}
123	
124		// Apply window: start after `after` cursor, end before `before` cursor.
125		startIdx := 0
126		if after != nil {
127			if afterID, ok := decodeStableCursor(*after); ok {
128				for i, e := range all {
129					if e.Node.ID == afterID {
130						startIdx = i + 1
131						break
132					}
133				}
134			}
135		}
136		endIdx := len(all)
137		if before != nil {
138			if beforeID, ok := decodeStableCursor(*before); ok {
139				for i, e := range all {
140					if e.Node.ID == beforeID {
141						endIdx = i
142						break
143					}
144				}
145			}
146		}
147		if startIdx > endIdx {
148			startIdx = endIdx
149		}
150	
151		slice := all[startIdx:endIdx]
152		if first != nil && *first >= 0 && *first < len(slice) {
153			slice = slice[:*first]
154		}
155		if last != nil && *last >= 0 && *last < len(slice) {
156			slice = slice[len(slice)-*last:]
157		}
158	
159		pageInfo := &PageInfo{
160			HasPreviousPage: startIdx > 0,
161			HasNextPage:     endIdx < len(all),
162		}
163		if len(slice) > 0 {
164			pageInfo.StartCursor = &slice[0].Cursor
165			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
166		}
167	
168		return &ProjectConnection{
169			Edges:      slice,
170			PageInfo:   pageInfo,
171			TotalCount: len(all),
172		}, nil
173	}
174	
175	func nodeInfoFromSnapshot(s NodeStateSnapshot) *NodeInfo {
176		return &NodeInfo{
177			ID:        s.ID,
178			Name:      s.Name,
179			StartedAt: s.StartedAt.UTC().Format(time.RFC3339),
180			LastSeen:  s.LastSeen.UTC().Format(time.RFC3339),
181		}
182	}
