97	// Documents is the resolver for the documents field with Relay cursor pagination.
98	func (r *queryResolver) Documents(ctx context.Context, first *int, after *string, last *int, before *string, typeArg *string) (*DocumentConnection, error) {
99		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
100		if err != nil {
101			return nil, fmt.Errorf("building document graph: %w", err)
102		}
103	
104		docs := graph.AllNodesForOutput()
105		sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
106	
107		// Apply optional type filter by path component.
108		if typeArg != nil && *typeArg != "" {
109			filtered := docs[:0]
110			for _, d := range docs {
111				if strings.Contains(d.Path, string([]rune{'/'})+*typeArg+string([]rune{'/'})) ||
112					strings.HasPrefix(d.Path, *typeArg+string([]rune{'/'})) {
113					filtered = append(filtered, d)
114				}
115			}
116			docs = filtered
117		}
118	
119		all := make([]*DocumentEdge, len(docs))
120		for i, d := range docs {
121			all[i] = &DocumentEdge{
122				Node:   docToGQL(d),
123				Cursor: encodeStableCursor(d.ID),
124			}
125		}
126	
127		startIdx := 0
128		if after != nil {
129			if afterID, ok := decodeStableCursor(*after); ok {
130				for i, e := range all {
131					if e.Node.ID == afterID {
132						startIdx = i + 1
133						break
134					}
135				}
136			}
137		}
138		endIdx := len(all)
139		if before != nil {
140			if beforeID, ok := decodeStableCursor(*before); ok {
141				for i, e := range all {
142					if e.Node.ID == beforeID {
143						endIdx = i
144						break
145					}
146				}
147			}
148		}
149		if startIdx > endIdx {
150			startIdx = endIdx
151		}
152	
153		slice := all[startIdx:endIdx]
154		if first != nil && *first >= 0 && *first < len(slice) {
155			slice = slice[:*first]
156		}
157		if last != nil && *last >= 0 && *last < len(slice) {
158			slice = slice[len(slice)-*last:]
159		}
160	
161		pageInfo := &PageInfo{
162			HasPreviousPage: startIdx > 0,
163			HasNextPage:     endIdx < len(all),
164		}
165		if len(slice) > 0 {
166			pageInfo.StartCursor = &slice[0].Cursor
167			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
168		}
169	
170		return &DocumentConnection{
171			Edges:      slice,
172			PageInfo:   pageInfo,
173			TotalCount: len(all),
174		}, nil
175	}
