215	// DocGraphIssues is the resolver for the docGraphIssues field. It returns the
216	// same structured issue list used by the full graph query so dashboards can
217	// pull integrity state independently of the heavy graph payload.
218	func (r *queryResolver) DocGraphIssues(ctx context.Context) ([]*GraphIssue, error) {
219		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
220		if err != nil {
221			return nil, fmt.Errorf("building document graph: %w", err)
222		}
223		return issuesToGQL(graph.Issues), nil
224	}
225	
226	// issuesToGQL converts docgraph.GraphIssue values into the GraphQL model.
227	// Always returns a non-nil slice so downstream clients can treat an empty
228	// graph the same as a healthy one (no optional chaining required).
229	func issuesToGQL(issues []docgraph.GraphIssue) []*GraphIssue {
230		out := make([]*GraphIssue, 0, len(issues))
231		for _, issue := range issues {
232			gql := &GraphIssue{
233				Kind:    string(issue.Kind),
234				Message: issue.Message,
235			}
236			if issue.Path != "" {
237				p := issue.Path
238				gql.Path = &p
239			}
240			if issue.ID != "" {
241				id := issue.ID
242				gql.ID = &id
243			}
244			if issue.RelatedPath != "" {
245				rp := issue.RelatedPath
246				gql.RelatedPath = &rp
247			}
248			out = append(out, gql)
249		}
250		return out
251	}
252	
253	// docToGQL converts a docgraph.Document to the GraphQL Document model.
254	func docToGQL(d docgraph.Document) *Document {
255		doc := &Document{
256			ID:         d.ID,
257			Path:       d.Path,
258			Title:      d.Title,
259			DependsOn:  d.DependsOn,
260			Inputs:     d.Inputs,
261			Dependents: d.Dependents,
262			ParkingLot: d.ParkingLot,
263		}
264		if doc.DependsOn == nil {
265			doc.DependsOn = []string{}
266		}
267		if doc.Inputs == nil {
268			doc.Inputs = []string{}
269		}
270		if doc.Dependents == nil {
271			doc.Dependents = []string{}
272		}
273		if d.Prompt != "" {
274			p := d.Prompt
275			doc.Prompt = &p
276		}
277		if d.Review.ReviewedAt != "" || d.Review.SelfHash != "" {
278			depsJSON, _ := json.Marshal(d.Review.Deps)
279			doc.Review = &DocumentReview{
280				SelfHash:   d.Review.SelfHash,
281				Deps:       string(depsJSON),
282				ReviewedAt: d.Review.ReviewedAt,
283			}
284		}
285		if d.ExecDef != nil {
286			active := d.ExecDef.Active
287			required := d.ExecDef.Required
288			graphSource := true
289			doc.ExecDef = &DocumentExecDef{
290				ArtifactIds: d.ExecDef.ArtifactIDs,
291				Active:      &active,
292				Required:    &required,
293				GraphSource: &graphSource,
294			}
295		}
296		return doc
297	}
