66	func personaToGQL(p *persona.Persona) *Persona {
67		source := p.Source
68		if source == "" {
69			source = persona.SourceLibrary
70		}
71		var filePath *string
72		if p.FilePath != "" {
73			fp := p.FilePath
74			filePath = &fp
75		}
76		return &Persona{
77			ID:          "persona-" + p.Name,
78			Name:        p.Name,
79			Roles:       p.Roles,
80			Description: p.Description,
81			Tags:        p.Tags,
82			Content:     p.Content,
83			Body:        p.Content,
84			Source:      source,
85			Bindings:    []*PersonaBinding{},
86			FilePath:    filePath,
87		}
88	}
