90	func personaConnectionFrom(personas []*Persona, first *int, after *string, last *int, before *string) *PersonaConnection {
91		all := make([]*PersonaEdge, len(personas))
92		ids := make([]string, len(personas))
93		for i, p := range personas {
94			all[i] = &PersonaEdge{Node: p, Cursor: encodeStableCursor(p.ID)}
95			ids[i] = p.ID
96		}
97		startIdx, endIdx := stablePageBounds(ids, after, before)
98		slice := all[startIdx:endIdx]
99		truncByFirst, truncByLast := false, false
100		if first != nil && *first >= 0 && *first < len(slice) {
101			slice = slice[:*first]
102			truncByFirst = true
103		}
104		if last != nil && *last >= 0 && *last < len(slice) {
105			slice = slice[len(slice)-*last:]
106			truncByLast = true
107		}
108		pageInfo := &PageInfo{
109			HasPreviousPage: startIdx > 0 || truncByLast,
110			HasNextPage:     endIdx < len(all) || truncByFirst,
111		}
112		if len(slice) > 0 {
113			pageInfo.StartCursor = &slice[0].Cursor
114			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
115		}
116		return &PersonaConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
117	}
