212	
213		// Rebuild graph to pick up the newly written file and return the document.
214		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
215		if err != nil {
216			// File was written; return a minimal document rather than failing.
217			return &Document{
218				ID:         cleaned,
219				Path:       cleaned,
220				DependsOn:  []string{},
221				Inputs:     []string{},
222				Dependents: []string{},
223			}, nil
224		}
225	
226		// Look up the document by its cleaned path.
227		if id, ok := graph.PathToID[cleaned]; ok {
228			if doc, ok := graph.Documents[id]; ok {
229				return docToGQL(*doc), nil
230			}
231		}
232	
233		// File written but not yet in graph (e.g., missing DDx frontmatter).
234		return &Document{
235			ID:         cleaned,
236			Path:       cleaned,
237			DependsOn:  []string{},
238			Inputs:     []string{},
239			Dependents: []string{},
240		}, nil
241	}
