693	// DocumentByPath is the resolver for the documentByPath field.
694	// It reads the document at the given path (relative to the docgraph root or
695	// library) and returns its metadata plus raw file content.
696	func (r *queryResolver) DocumentByPath(ctx context.Context, path string) (*Document, error) {
697		if path == "" {
698			return nil, fmt.Errorf("path is required")
699		}
700	
701		cleaned, err := cleanDocumentPath(r.WorkingDir, path)
702		if err != nil {
703			return nil, err
704		}
705	
706		// Prefer the docgraph-tracked location: the documents list surfaces files
707		// walked under workingDir, so the detail view must read from the same root
708		// (otherwise the URL for a valid list entry 404s).
709		if graph, graphErr := docgraph.BuildGraphWithConfig(r.WorkingDir); graphErr == nil {
710			if id, ok := graph.PathToID[cleaned]; ok {
711				if d, ok := graph.Documents[id]; ok {
712					absPath := d.Path
713					if !filepath.IsAbs(absPath) {
714						absPath = filepath.Join(graph.RootDir, absPath)
715					}
716					if data, readErr := os.ReadFile(absPath); readErr == nil {
717						content := string(data)
718						doc := docToGQL(*d)
719						doc.Content = &content
720						return doc, nil
721					}
722				}
723			}
724		}
725	
726		// Fall back to the configured library path so documents created via the
727		// documentWrite mutation (which target the library) remain readable even
728		// when they have no DDx frontmatter and so do not appear in the graph.
729		cfg, err := config.LoadWithWorkingDir(r.WorkingDir)
730		if err != nil {
731			return nil, fmt.Errorf("loading config: %w", err)
732		}
733		if cfg.Library == nil || cfg.Library.Path == "" {
734			return nil, nil
735		}
736		libPath := cfg.Library.Path
737		if !filepath.IsAbs(libPath) {
738			libPath = filepath.Join(r.WorkingDir, libPath)
739		}
740	
741		fullPath := filepath.Join(libPath, cleaned)
742		data, err := os.ReadFile(fullPath)
743		if err != nil {
744			return nil, nil // not found → null
745		}
746		content := string(data)
747	
748		return &Document{
749			ID:         cleaned,
750			Path:       cleaned,
751			DependsOn:  []string{},
752			Inputs:     []string{},
753			Dependents: []string{},
754			Content:    &content,
755		}, nil
756	}

