842	// Artifacts is the resolver for the artifacts query.
843	// It returns a paginated, optionally-filtered list of DDx-tracked artifacts
844	// for the given project. Documents come from the FEAT-007 doc graph; other
845	// artifacts come from .ddx.yaml sidecar files found under .ddx/plugins/.
846	func (r *queryResolver) Artifacts(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, mediaType *string, search *string) (*ArtifactConnection, error) {
847		root := r.projectRoot(projectID)
848	
849		artifacts, err := collectArtifacts(root)
850		if err != nil {
851			return nil, fmt.Errorf("collecting artifacts: %w", err)
852		}
853	
854		// Sort by path for stable ordering.
855		sort.Slice(artifacts, func(i, j int) bool {
856			return artifacts[i].Path < artifacts[j].Path
857		})
858	
859		// Apply mediaType filter.
860		if mediaType != nil && *mediaType != "" {
861			mt := *mediaType
862			filtered := artifacts[:0]
863			for _, a := range artifacts {
864				if a.MediaType == mt {
865					filtered = append(filtered, a)
866				}
867			}
868			artifacts = filtered
869		}
870	
871		// Apply search filter across title and path.
872		if search != nil && *search != "" {
873			q := strings.ToLower(*search)
874			filtered := artifacts[:0]
875			for _, a := range artifacts {
876				if strings.Contains(strings.ToLower(a.Title), q) ||
877					strings.Contains(strings.ToLower(a.Path), q) {
878					filtered = append(filtered, a)
879				}
880			}
881			artifacts = filtered
882		}
883	
884		// Build Relay edges.
885		all := make([]*ArtifactEdge, len(artifacts))
886		for i, a := range artifacts {
887			cp := a
888			all[i] = &ArtifactEdge{
889				Node:   cp,
890				Cursor: encodeStableCursor(cp.ID),
891			}
892		}
893	
894		startIdx := 0
895		if after != nil {
896			if afterID, ok := decodeStableCursor(*after); ok {
897				for i, e := range all {
898					if e.Node.ID == afterID {
899						startIdx = i + 1
900						break
901					}
902				}
903			}
904		}
905		endIdx := len(all)
906		if before != nil {
907			if beforeID, ok := decodeStableCursor(*before); ok {
908				for i, e := range all {
909					if e.Node.ID == beforeID {
910						endIdx = i
911						break
912					}
913				}
914			}
915		}
916		if startIdx > endIdx {
917			startIdx = endIdx
918		}
919	
920		windowSize := endIdx - startIdx
921		slice := all[startIdx:endIdx]
922		if first != nil && *first >= 0 && *first < len(slice) {
923			slice = slice[:*first]
924		}
925		if last != nil && *last >= 0 && *last < len(slice) {
926			slice = slice[len(slice)-*last:]
927		}
928	
929		pageInfo := &PageInfo{
930			HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
931			HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
932		}
933		if len(slice) > 0 {
934			pageInfo.StartCursor = &slice[0].Cursor
935			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
936		}
937	
938		return &ArtifactConnection{
939			Edges:      slice,
940			PageInfo:   pageInfo,
941			TotalCount: len(all),
942		}, nil
943	}
