965			all[i] = &CommitEdge{
966				Node:   c,
967				Cursor: encodeStableCursor(c.Sha),
968			}
969		}
970	
971		// Apply window: start after `after` cursor, end before `before` cursor.
972		startIdx := 0
973		if after != nil {
974			if afterSha, ok := decodeStableCursor(*after); ok {
975				for i, e := range all {
976					if e.Node.Sha == afterSha {
977						startIdx = i + 1
978						break
979					}
980				}
981			}
982		}
983		endIdx := len(all)
984		if before != nil {
985			if beforeSha, ok := decodeStableCursor(*before); ok {
986				for i, e := range all {
987					if e.Node.Sha == beforeSha {
988						endIdx = i
989						break
990					}
991				}
992			}
993		}
994		if startIdx > endIdx {
995			startIdx = endIdx
996		}
997	
998		windowSize := endIdx - startIdx
999		slice := all[startIdx:endIdx]
1000		if first != nil && *first >= 0 && *first < len(slice) {
1001			slice = slice[:*first]
1002		}
1003		if last != nil && *last >= 0 && *last < len(slice) {
1004			slice = slice[len(slice)-*last:]
1005		}
1006	
1007		pageInfo := &PageInfo{
1008			HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
1009			HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
1010		}
1011		if len(slice) > 0 {
1012			pageInfo.StartCursor = &slice[0].Cursor
1013			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
1014		}
1015	
1016		return &CommitConnection{
1017			Edges:      slice,
1018			PageInfo:   pageInfo,
1019			TotalCount: len(all),
1020		}, nil
1021	}
