1360	// ProviderStatuses is the resolver for the providerStatuses field.
1361	// It mirrors the output of `ddx agent providers`, annotating each row with
1362	// kind=ENDPOINT, a lastCheckedAt timestamp, and rolling usage derived from
1363	// the sessions index. Quota is populated when the upstream ProviderInfo
1364	// exposes token-level quota headers; null otherwise (FEAT-014 no-fabrication).
1365	func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
1366		now := time.Now().UTC()
1367		entries := r.sessionIndexEntries()
1368	
1369		if rows := cachedProviderRows(r.WorkingDir); len(rows) > 0 {
1370			refreshProviderStatuses(r.WorkingDir)
1371			return providerRowsWithUsage(rows, entries, now), nil
1372		}
1373	
1374		if snapshots, ok, err := agent.ConfiguredProviderSnapshots(r.WorkingDir); err == nil && ok {
1375			rows := providerStatusesFromInfos(snapshots, entries, now)
1376			storeProviderRows(r.WorkingDir, rows)
1377			refreshProviderStatuses(r.WorkingDir)
1378			return rows, nil
1379		} else if err != nil {
1380			return nil, fmt.Errorf("loading provider snapshots: %w", err)
1381		}
1382	
1383		// Legacy/global provider config fallback. Bound the synchronous path so the
1384		// UI can still first-paint harness rows even if provider probing is slow.
1385		probeCtx, cancel := context.WithTimeout(ctx, 500*time.Millisecond)
1386		defer cancel()
1387		providers, err := liveProviderInfos(probeCtx, r.WorkingDir)
1388		if err != nil {
1389			refreshProviderStatuses(r.WorkingDir)
1390			return []*ProviderStatus{}, nil
1391		}
1392		rows := providerStatusesFromInfos(providers, entries, now)
1393		storeProviderRows(r.WorkingDir, rows)
1394		return rows, nil
1395	}
