1397	// HarnessStatuses is the resolver for the harnessStatuses field.
1398	// It returns one row per subprocess harness (kind=HARNESS). Reachability is
1399	// taken from HarnessInfo.Available, rolling usage from the sessions index,
1400	// and quota from the harness-reported rate-limit data when available.
1401	func (r *queryResolver) HarnessStatuses(ctx context.Context) ([]*ProviderStatus, error) {
1402		svc, err := agentlib.New(agentlib.ServiceOptions{})
1403		if err != nil {
