1405		}
1406		infos, err := svc.ListHarnesses(ctx)
1407		if err != nil {
1408			return nil, fmt.Errorf("listing harnesses: %w", err)
1409		}
1410	
1411		now := time.Now().UTC()
1412		entries := r.sessionIndexEntries()
1413		lastChecked := now.Format(time.RFC3339)
1414	
1415		results := make([]*ProviderStatus, 0, len(infos))
1416		for _, info := range infos {
1417			ps := &ProviderStatus{
1418				Name:              info.Name,
1419				Kind:              ProviderKindHarness,
1420				ProviderType:      harnessTypeLabel(info),
1421				BaseURL:           "(subprocess)",
1422				Model:             info.DefaultModel,
1423				Status:            harnessStatusLine(info),
1424				Reachable:         info.Available,
1425				Detail:            harnessDetail(info),
1426				ModelCount:        harnessModelCount(info),
1427				IsDefault:         false,
