1462	// ProviderTrend is the resolver for the providerTrend field.
1463	// It aggregates the sessions index into time buckets for one provider/harness
1464	// and computes a projected-run-out-in-hours callout from the last-24h slope.
1465	func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
1466		name = strings.TrimSpace(name)
1467		if name == "" {
1468			return nil, fmt.Errorf("name required")
1469		}
1470		if windowDays != 7 && windowDays != 30 {
1471			return nil, fmt.Errorf("windowDays must be 7 or 30")
1472		}
1473		now := time.Now().UTC()
1474		entries := r.sessionIndexEntries()
1475	
1476		kind, detected := detectProviderOrHarness(ctx, r, name)
1477		bucketKind := agent.MatchProvider
1478		if kind == ProviderKindHarness {
1479			bucketKind = agent.MatchHarness
1480		}
1481	
1482		bucketSize := time.Hour
1483		if windowDays > 7 {
1484			bucketSize = 4 * time.Hour
1485		}
1486		buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
1487		series := make([]*ProviderTrendPoint, 0, len(buckets))
1488		for _, b := range buckets {
1489			series = append(series, &ProviderTrendPoint{
1490				BucketStart: b.Start.UTC().Format(time.RFC3339),
1491				Tokens:      b.Tokens,
1492				Requests:    b.Requests,
1493			})
1494		}
1495	
1496		trend := &ProviderTrend{
1497			Name:       name,
1498			Kind:       kind,
1499			WindowDays: windowDays,
1500			Series:     series,
1501		}
1502	
1503		if detected != nil {
1504			if ceiling := detected.ceilingTokens; ceiling > 0 {
1505				c := ceiling
1506				trend.CeilingTokens = &c
1507				remaining := detected.remaining
1508				if remaining < 0 {
1509					remaining = ceiling - sumTailTokens(buckets, 24)
1510				}
1511				if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
1512					trend.ProjectedRunOutHours = &p
1513				}
1514			}
1515		}
1516	
1517		return trend, nil
